class Solution(object):
    def findTheArrayConcVal(self, nums):
        result = 0
        while nums:
            if len(nums) == 1:
                result += nums[0]
                break
            first = nums.pop(0)
            last = nums.pop()
            result += int(str(first) + str(last))
        return result
